#include <stdio.h>
#include <stdint.h>

static inline int64_t countOnes(int64_t N, int k){
    int64_t total = N + 1;
    int64_t cycle = 1LL << (k + 1);
    int64_t full = total / cycle;
    int64_t rem = total % cycle;
    int64_t ones = full * (1LL << k) + (rem > (1LL << k) ? rem - (1LL << k) : 0);
    return ones;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        uint32_t X, Y, N; scanf("%u %u %u", &X, &Y, &N);
        if (X == Y){
            printf("0\n");
            continue;
        }
        uint32_t diff = X ^ Y;
        int k = 31 - __builtin_clz(diff); // highest differing bit
        int needOne = ((X >> k) & 1) ? 0 : 1; // need Z_k = 1 when X_k=0,Y_k=1 else 0
        int64_t ones = countOnes(N, k);
        int64_t total = (int64_t)N + 1;
        int64_t ans = needOne ? ones : (total - ones);
        printf("%lld\n", ans);
    }
    return 0;
}

