import java.io.*;
import java.util.*;

public class Main {
    private static long countOnes(long N, int k){
        long total = N + 1;
        long cycle = 1L << (k + 1);
        long full = total / cycle;
        long rem = total % cycle;
        long ones = full * (1L << k) + Math.max(0L, rem - (1L << k));
        return ones;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long X = Long.parseLong(st.nextToken());
            long Y = Long.parseLong(st.nextToken());
            long N = Long.parseLong(st.nextToken());
            if (X == Y) {
                sb.append(0).append('\n');
                continue;
            }
            long diff = X ^ Y;
            int k = 63 - Long.numberOfLeadingZeros(diff);
            int needOne = ((X >> k) & 1L) == 1L ? 0 : 1; // need Z_k = 1 when X_k=0
            long ones = countOnes(N, k);
            long total = N + 1;
            long ans = needOne == 1 ? ones : (total - ones);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

